import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import API from '../api/axios';

const TABS = ['overview','users','appointments','services'];

export default function AdminDashboard() {
  const [data, setData] = useState({ users:[], appointments:[], services:[] });
  const [tab, setTab] = useState('overview');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([API.get('/admin/users'), API.get('/admin/appointments'), API.get('/services')])
      .then(([u, a, s]) => { setData({ users:u.data, appointments:a.data, services:s.data }); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const deleteUser = async id => {
    if (!window.confirm('Delete this user?')) return;
    await API.delete(`/admin/users/${id}`);
    setData(p => ({ ...p, users: p.users.filter(u => u._id !== id) }));
    toast.success('User deleted');
  };

  const updateStatus = async (id, status) => {
    await API.put(`/appointments/${id}/status`, { status });
    setData(p => ({ ...p, appointments: p.appointments.map(a => a._id === id ? { ...a, status } : a) }));
    toast.success('Status updated');
  };

  const cards = [
    { label:'Total Users',   value: data.users.length,                                   icon:'👥', color:'#818cf8' },
    { label:'Providers',     value: data.users.filter(u => u.role==='provider').length,  icon:'🏪', color:'#34d399' },
    { label:'Appointments',  value: data.appointments.length,                             icon:'📅', color:'#c084fc' },
    { label:'Services',      value: data.services.length,                                 icon:'⭐', color:'#fbbf24' },
  ];

  return (
    <div style={{ minHeight:'100vh', background:'#0a0a0f', padding:'100px 40px 60px' }}>
      <div style={{ maxWidth:'1200px', margin:'0 auto' }}>

        {/* Title */}
        <div style={{ display:'flex', alignItems:'center', gap:'16px', marginBottom:'40px' }}>
          <div style={{ width:52, height:52, borderRadius:'14px', background:'rgba(248,113,113,0.15)', border:'1px solid rgba(248,113,113,0.25)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px' }}>🛡️</div>
          <div>
            <h1 style={{ fontSize:'30px', fontWeight:800, color:'#f1f5f9' }}>Admin Dashboard</h1>
            <p style={{ color:'#475569', fontSize:'14px', marginTop:'2px' }}>Full system control panel</p>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:'flex', gap:'6px', marginBottom:'32px', background:'rgba(255,255,255,0.04)', padding:'5px', borderRadius:'12px', width:'fit-content', border:'1px solid rgba(255,255,255,0.07)' }}>
          {TABS.map(t => (
            <button key={t} onClick={() => setTab(t)} style={{
              padding:'8px 22px', borderRadius:'9px', border:'none', cursor:'pointer',
              fontWeight:600, fontSize:'13px', transition:'all 0.25s', textTransform:'capitalize',
              background: tab===t ? 'linear-gradient(135deg,#6366f1,#8b5cf6)' : 'transparent',
              color: tab===t ? '#fff' : '#64748b'
            }}>{t}</button>
          ))}
        </div>

        {loading ? (
          <div style={{ textAlign:'center', padding:'80px', color:'#475569' }}>
            <div style={{ fontSize:'36px', animation:'float 1s infinite' }}>⏳</div>
          </div>
        ) : (
          <>
            {/* Overview */}
            {tab==='overview' && (
              <div>
                <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(220px,1fr))', gap:'18px', marginBottom:'28px' }}>
                  {cards.map((c,i) => (
                    <div key={i} className="glass" style={{ padding:'22px', display:'flex', alignItems:'center', gap:'16px' }}>
                      <div style={{ width:50, height:50, borderRadius:'13px', background:`${c.color}18`, border:`1px solid ${c.color}30`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'24px' }}>{c.icon}</div>
                      <div>
                        <div style={{ fontSize:'30px', fontWeight:800, color:c.color }}>{c.value}</div>
                        <div style={{ fontSize:'12px', color:'#64748b', marginTop:'2px' }}>{c.label}</div>
                      </div>
                    </div>
                  ))}
                </div>
                <div className="glass" style={{ padding:'24px' }}>
                  <h3 style={{ marginBottom:'18px', color:'#94a3b8', fontSize:'15px', fontWeight:600 }}>RECENT APPOINTMENTS</h3>
                  {data.appointments.slice(0,6).map(a => (
                    <div key={a._id} style={{ display:'flex', justifyContent:'space-between', padding:'13px 0', borderBottom:'1px solid rgba(255,255,255,0.05)', alignItems:'center' }}>
                      <div>
                        <span style={{ fontWeight:600, color:'#e2e8f0', fontSize:'14px' }}>{a.service?.name}</span>
                        <span style={{ color:'#475569', fontSize:'12px', marginLeft:'12px' }}>{a.customer?.name} → {a.provider?.name}</span>
                      </div>
                      <span className={`badge badge-${a.status}`}>{a.status}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Users */}
            {tab==='users' && (
              <div className="glass" style={{ padding:'24px', overflowX:'auto' }}>
                <h3 style={{ marginBottom:'20px', color:'#94a3b8', fontSize:'15px', fontWeight:600 }}>ALL USERS ({data.users.length})</h3>
                <table style={{ width:'100%', borderCollapse:'collapse' }}>
                  <thead>
                    <tr>
                      {['Name','Email','Role','Joined','Action'].map(h => (
                        <th key={h} style={{ padding:'11px 14px', textAlign:'left', color:'#475569', fontSize:'12px', fontWeight:700, borderBottom:'1px solid rgba(255,255,255,0.07)', textTransform:'uppercase', letterSpacing:'0.5px' }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {data.users.map(u => (
                      <tr key={u._id} style={{ borderBottom:'1px solid rgba(255,255,255,0.04)' }}>
                        <td style={{ padding:'13px 14px', color:'#e2e8f0', fontWeight:600, fontSize:'14px' }}>{u.name}</td>
                        <td style={{ padding:'13px 14px', color:'#64748b', fontSize:'13px' }}>{u.email}</td>
                        <td style={{ padding:'13px 14px' }}>
                          <span style={{
                            padding:'3px 10px', borderRadius:'20px', fontSize:'12px', fontWeight:600,
                            background: u.role==='admin' ? 'rgba(248,113,113,0.15)' : u.role==='provider' ? 'rgba(52,211,153,0.15)' : 'rgba(129,140,248,0.15)',
                            color: u.role==='admin' ? '#f87171' : u.role==='provider' ? '#34d399' : '#818cf8'
                          }}>{u.role}</span>
                        </td>
                        <td style={{ padding:'13px 14px', color:'#475569', fontSize:'13px' }}>{new Date(u.createdAt).toLocaleDateString()}</td>
                        <td style={{ padding:'13px 14px' }}>
                          {u.role !== 'admin' && (
                            <button onClick={() => deleteUser(u._id)} style={{ background:'rgba(248,113,113,0.1)', color:'#f87171', border:'1px solid rgba(248,113,113,0.25)', padding:'5px 12px', borderRadius:'7px', cursor:'pointer', fontSize:'12px', fontWeight:600 }}>Delete</button>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}

            {/* Appointments */}
            {tab==='appointments' && (
              <div className="glass" style={{ padding:'24px' }}>
                <h3 style={{ marginBottom:'20px', color:'#94a3b8', fontSize:'15px', fontWeight:600 }}>ALL APPOINTMENTS ({data.appointments.length})</h3>
                {data.appointments.map(a => (
                  <div key={a._id} style={{ padding:'15px', marginBottom:'10px', background:'rgba(255,255,255,0.02)', borderRadius:'10px', border:'1px solid rgba(255,255,255,0.06)', display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'10px' }}>
                    <div>
                      <span style={{ fontWeight:700, color:'#e2e8f0', fontSize:'14px' }}>{a.service?.name}</span>
                      <span style={{ color:'#475569', fontSize:'12px', display:'block', marginTop:'3px' }}>{a.customer?.name} → {a.provider?.name} &nbsp;|&nbsp; {a.date} {a.timeSlot}</span>
                    </div>
                    <div style={{ display:'flex', gap:'8px', alignItems:'center' }}>
                      <span className={`badge badge-${a.status}`}>{a.status}</span>
                      <select onChange={e => updateStatus(a._id, e.target.value)} value={a.status}
                        style={{ background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.12)', color:'#94a3b8', padding:'5px 10px', borderRadius:'7px', fontSize:'12px', cursor:'pointer' }}>
                        {['pending','confirmed','cancelled','completed'].map(s => <option key={s} value={s}>{s}</option>)}
                      </select>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Services */}
            {tab==='services' && (
              <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(270px,1fr))', gap:'18px' }}>
                {data.services.map(s => (
                  <div key={s._id} className="glass" style={{ padding:'20px' }}>
                    <h4 style={{ marginBottom:'7px', color:'#e2e8f0', fontSize:'15px', fontWeight:700 }}>{s.name}</h4>
                    <p style={{ color:'#475569', fontSize:'13px', marginBottom:'14px', lineHeight:1.5 }}>{s.description}</p>
                    <div style={{ display:'flex', justifyContent:'space-between', fontSize:'13px' }}>
                      <span style={{ color:'#64748b' }}>⏱ {s.duration} mins</span>
                      <span style={{ color:'#818cf8', fontWeight:700 }}>₹{s.price}</span>
                    </div>
                    <div style={{ fontSize:'12px', color:'#475569', marginTop:'9px' }}>👤 {s.provider?.name}</div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}
